'use client';

import { ContextMenu } from '@base-ui/react/context-menu';
import { cx } from 'antd-style';
import { memo, useEffect, useMemo, useSyncExternalStore } from 'react';

import { useIsClient } from '@/hooks/useIsClient';
import { useAppElement } from '@/ThemeProvider';
import { registerDevSingleton } from '@/utils/devSingleton';
import { preventDefaultAndStopPropagation } from '@/utils/dom';

import { useLayerZIndex } from '../zIndex';
import { renderContextMenuItems } from './renderItems';
import {
  closeContextMenu,
  getServerSnapshot,
  getSnapshot,
  setContextMenuState,
  subscribe,
  updateLastPointer,
} from './store';
import { styles } from './style';

const noAnimationStyles = { '--lobe-dropdown-animation-duration': '0ms' } as React.CSSProperties;

export const ContextMenuHost = memo(() => {
  const isClient = useIsClient();
  const appElement = useAppElement();
  const state = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);

  useEffect(() => {
    const DEV = process.env.NODE_ENV === 'development';
    if (!isClient || !DEV) return;
    return registerDevSingleton('ContextMenuHost', document.body);
  }, [isClient]);

  useEffect(() => {
    const handler = (event: MouseEvent | PointerEvent) => updateLastPointer(event);
    window.addEventListener('pointerdown', handler, true);
    window.addEventListener('contextmenu', handler, true);
    return () => {
      window.removeEventListener('pointerdown', handler, true);
      window.removeEventListener('contextmenu', handler, true);
    };
  }, []);

  const menuItems = useMemo(
    () =>
      renderContextMenuItems(state.items, [], {
        iconAlign: state.iconAlign,
        iconSpaceMode: state.iconSpaceMode,
      }),
    [state.items, state.iconAlign, state.iconSpaceMode],
  );
  const { zIndex, ref: zRef } = useLayerZIndex<HTMLDivElement>('floating');
  const hasSlots = state.header != null || state.footer != null;
  if (!isClient) return null;
  if (!state.open && state.items.length === 0) return null;

  return (
    <ContextMenu.Root
      open={state.open}
      onOpenChange={(open) => {
        if (open) {
          setContextMenuState({ open });
          return;
        }
        closeContextMenu();
      }}
    >
      <ContextMenu.Portal container={appElement}>
        <ContextMenu.Positioner
          anchor={state.anchor ?? undefined}
          className={styles.positioner}
          ref={zRef as any}
          sideOffset={6}
          style={{ ...noAnimationStyles, zIndex }}
        >
          <ContextMenu.Popup
            className={cx(styles.popup, hasSlots && styles.popupWithSlots)}
            data-has-footer={state.footer == null ? undefined : ''}
            data-has-header={state.header == null ? undefined : ''}
            onContextMenu={preventDefaultAndStopPropagation}
          >
            {state.header == null ? null : <div className={styles.header}>{state.header}</div>}
            {hasSlots ? <div className={styles.slotViewport}>{menuItems}</div> : menuItems}
            {state.footer == null ? null : <div className={styles.footer}>{state.footer}</div>}
          </ContextMenu.Popup>
        </ContextMenu.Positioner>
      </ContextMenu.Portal>
    </ContextMenu.Root>
  );
});

ContextMenuHost.displayName = 'ContextMenuHost';
